{
  "summary": "The paper proposes using document similarity metrics to mine noisy parallel code datasets from large monolingual corpora, enabling supervised code translation across multiple programming languages without expensive manual curation. Experiments show that models trained on these noisy datasets maintain strong performance and that Word Movers Distance is particularly effective for mining parallel pairs.",
  "strengths": [
    {
      "point": "Novel approach to create large-scale noisy parallel code datasets using document similarity metrics",
      "evidence": "The method leverages various similarity metrics (WMD, TF-IDF, BM25, etc.) to pair code documents across languages, enabling supervised training without curated parallel data."
    },
    {
      "point": "Demonstrated robustness of code translation models to noise in training data",
      "evidence": "Models trained on noisy mined datasets perform comparably to those trained on ground truth data, with gradual performance degradation as noise increases."
    },
    {
      "point": "Expanded supervised code translation to 10 language pairs beyond prior work",
      "evidence": "Applied the method to CodeNet data covering 10 language pairs and showed improved translation accuracy over random pairing baselines."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of empirical comparison to strong unsupervised and semi-supervised baselines",
      "evidence": "No evaluation against recent methods like CodeT5 or large pretrained models on the same datasets and metrics to contextualize gains."
    },
    {
      "point": "Insufficient analysis and tuning of critical hyperparameters such as similarity threshold",
      "evidence": "No ablation or sensitivity study on how threshold choice affects noise rate, dataset size, or downstream performance."
    },
    {
      "point": "Missing exploration of combining multiple similarity metrics for improved pair mining",
      "evidence": "Only individual metrics evaluated; no experiments on metric fusion or ensemble approaches to reduce noise."
    },
    {
      "point": "Limited semantic evaluation beyond unit tests and CodeBLEU",
      "evidence": "No use of deeper semantic equivalence checks or human expert assessments to validate translation correctness."
    },
    {
      "point": "Reproducibility concerns due to missing preprocessing and hyperparameter details",
      "evidence": "No description of code preprocessing steps or hyperparameters for similarity metrics like WMD and BM25."
    },
    {
      "point": "Partial dataset release limits full replication of large-scale experiments",
      "evidence": "Only partial datasets are released, hindering exact reproduction of mined parallel corpora."
    },
    {
      "point": "No discussion of computational efficiency or scalability of similarity computations",
      "evidence": "Applying expensive metrics like WMD at scale is not analyzed or optimized."
    },
    {
      "point": "Lack of qualitative analysis illustrating noise impact on model outputs",
      "evidence": "No error analysis or examples showing how noisy pairs affect translation errors or negative transfer."
    },
    {
      "point": "No analysis of language-specific challenges or finer-grained code context in pairing",
      "evidence": "No discussion on syntax, idiomatic differences, or function-level alignment that could affect pairing quality."
    },
    {
      "point": "Evaluation limited to popular languages and competitive programming datasets",
      "evidence": "No experiments on low-resource or real-world legacy codebases, limiting generalizability claims."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed method compare empirically to recent unsupervised or semi-supervised code translation approaches?",
      "motivation": "Understanding relative performance is critical to assess practical impact and novelty."
    },
    {
      "question": "What is the effect of varying the similarity threshold on the noise level and downstream translation accuracy?",
      "motivation": "Threshold tuning is key to controlling dataset quality and model performance."
    },
    {
      "question": "Can combining multiple similarity metrics improve the quality of mined parallel pairs?",
      "motivation": "Metric fusion may reduce noise and enhance translation results."
    },
    {
      "question": "How do language-specific syntax and idiomatic differences affect similarity scores and translation quality?",
      "motivation": "Insights here could guide metric design and improve applicability across diverse languages."
    },
    {
      "question": "What are the computational costs and scalability considerations for mining large-scale parallel datasets using expensive metrics like WMD?",
      "motivation": "Practical deployment requires efficient and scalable methods."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
